import{_ as a}from"./KNrs7nZb.js";import{T as i}from"./DBzdA5KT.js";import{_ as o,c as n,b as s,j as d,w as t,a as l,o as c}from"./BAnZIRC2.js";import{u as r}from"./CGYW6dQL.js";const u={id:"main",class:"case-study"},h={__name:"case-study-article",setup(p){return r({title:"Dicapta Case Studies | Real-World Examples of Accessible Media Solutions",meta:[{hid:"description",name:"description",content:"Discover Dicapta's case studies, showcasing real-world examples of our innovative accessibility solutions in action. See how we enhance media for all audiences."}]}),(m,e)=>(c(),n("main",u,[e[2]||(e[2]=s("p",{class:"case-study__date blue-background"},"12 MAY 2024",-1)),e[3]||(e[3]=s("section",{class:"blue-background case-study__first-section"},[s("h1",{class:"case-study__title"}," Empowering Accessibility: How All4Access Technology Transformed Access for a Blind Student at Johns Hopkins ")],-1)),s("section",null,[d(i,null,{"left-column":t(()=>e[0]||(e[0]=[s("h2",null,"Summary:",-1),s("p",null," A blind Johns Hopkins student was taking a Turkish culture class, but she could not access the course's video materials. Thanks to the use of Dicapta's All4Access technology, the student received the necessary tools to access the material and be on equal footing with her classmates. ",-1)])),"right-column":t(()=>e[1]||(e[1]=[s("img",{src:a,alt:"",width:"800",height:"534"},null,-1)])),_:1})]),e[4]||(e[4]=l('<section class="blue-background" data-v-0e7a9dfb><h2 data-v-0e7a9dfb>The challenge:</h2><p data-v-0e7a9dfb> The Student Disability Services Office at Johns Hopkins University needed to provide access to movies in Turkish and Kurdish language to a blind student. The movies were part of a cultural course and had English subtitles. It was important to hear the film&#39;s original dialogues because they conveyed part of the cultural ambiance of the film. Since the student didn&#39;t have access to the film&#39;s visual elements and couldn&#39;t read the subtitles, it was necessary to find a way to solve both issues at once in a way that provided the student with a seamless experience. Dicapta provided several options, including creating a voiceover to give access to the subtitles, and worked with the student and the team at Johns Hopkins to determine the best way to give access to the film. </p></section><section data-v-0e7a9dfb><h2 data-v-0e7a9dfb>The solution:</h2><p data-v-0e7a9dfb> Dicapta created audio descriptions to provide access to the film&#39;s visuals and uploaded them to the All4Access platform. At the same time, since the university provided the English subtitles files, we were able to also upload the subtitles to All4Access. The student used the all4Access app to listen to the audio description and access the subtitles in her braille display. </p></section><section class="blue-background" data-v-0e7a9dfb><h2 data-v-0e7a9dfb>The results:</h2><p data-v-0e7a9dfb> The student was able to access the same information her classmates received and realized that she could enjoy a movie; as she previously mentioned, she only had an interest in books because of the accessibility barriers. The Student Disability Services Office was able to solve the accessibility challenge for this particular student and also determined that the All4Access technology was a versatile tool for solving students with disabilities&#39; access challenges. The Johns Hopkins team described All4Access as &quot;a pipe dream.&quot; </p></section><section data-v-0e7a9dfb><p data-v-0e7a9dfb> &quot;The experience of using All4Access to provide access for our student was great! I have never appreciated small business more, as we were able to work so closely together and provide feedback throughout the term to make sure that the student was getting the access she needed as well as preferred.&quot; </p><p data-v-0e7a9dfb>Julie Clementson,</p><p data-v-0e7a9dfb> Accessibility and Assistive Technology Coordinator, Student Disability Services at Johns Hopkins University. </p></section><section class="blue-background case-study__last-section" data-v-0e7a9dfb><h2 data-v-0e7a9dfb>About Johns Hopkins:</h2><p data-v-0e7a9dfb> Johns Hopkins University, founded in 1876, is America&#39;s first research university. Renowned for its nine world-class academic divisions, it serves nearly 24,000 students across various disciplines. Located in Baltimore, MD, Johns Hopkins also extends its reach globally with graduate campuses in Italy, China, and Washington, D.C., fostering a diverse and expansive academic community. </p></section>',5))]))}},g=o(h,[["__scopeId","data-v-0e7a9dfb"]]);export{g as default};
